#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int A[N], B[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        for (int i = 0; i < N; i++) {
            scanf("%d", &B[i]);
        }
        qsort(A, N, sizeof(int), compare);
        qsort(B, N, sizeof(int), compare);
        int count = 0;
        for (int i = 0; i < N; i++) {
            char str1[20], str2[20];
            sprintf(str1, "%d%d", A[N-1-i], B[N-1-i]);
            sprintf(str2, "%d%d", B[N-1-i], A[N-1-i]);
            if (atoi(str1) > atoi(str2)) {
                count++;
            }
        }
        printf("%f\n", (float)count / (float)N);
    }
    return 0;
}

