code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int[] A = new int[N];
            int[] B = new int[N];
            for (int i = 0; i < N; i++) {
                A[i] = sc.nextInt();
            }
            for (int i = 0; i < N; i++) {
                B[i] = sc.nextInt();
            }
            Arrays.sort(A);
            Arrays.sort(B);
            int count = 0;
            for (int i = 0; i < N; i++) {
                String str1 = String.valueOf(A[N-1-i]) + String.valueOf(B[N-1-i]);
                String str2 = String.valueOf(B[N-1-i]) + String.valueOf(A[N-1-i]);
                if (Integer.parseInt(str1) > Integer.parseInt(str2)) {
                    count++;
                }
            }
            System.out.println((float)count / (float)N);
        }
    }
}

