const lines = require('fs').readFileSync(0, 'utf-8').trim().split('\n');
let i = 0;
const readline = () => lines[i++];

const T = parseInt(readline());
for (let t = 0; t < T; t++) {
    const N = parseInt(readline());
    const A = readline().split(' ').map(x => parseInt(x));
    const B = readline().split(' ').map(x => parseInt(x));
    A.sort((a, b) => a - b);
    B.sort((a, b) => a - b);
    let count = 0;
    for (let i = 0; i < N; i++) {
        const str1 = A[N-1-i] + '' + B[N-1-i];
        const str2 = B[N-1-i] + '' + A[N-1-i];
        if (parseInt(str1) > parseInt(str2)) {
            count++;
        }
    }
    console.log(count / N);
}

